//# Synchronous Muller C-Element

// This is a synchronous (clocked) version of the Muller C-Element, which
// implements a *rendez-vous* or *join* function: the output remains low until
// all inputs go high, then the output remains high until all inputs have gone
// back low.

// The minimum `PIPE_DEPTH` is 1. Increase it as necessary to meet timing
// if you have a large number of inputs.

// Bringing `clock_enable` low will freeze the operation of the C-Element
// until brought back high. Inputs may change during that time, but they will
// not be registered, and the pipeline contents remain unchanged. Raising
// `clear` will empty the internal pipeline and bring the output low.

//## Uses

// * A chain of C-Elements can act as the control path for a Muller pipeline,
// which automatically pushes items forward as space allows. (This is
// a classic design in asychronous logic literature.)
// * A C-Element can act as a barrier to synchronize independent calculations:
// all calculations reaching a given point can signal the C-Element and stop
// until the C-Element output goes high, then continue calculating and halt
// again if they reach the same point while the C-Element output is still high,
// then signal it again once the output goes low.  A [Pulse
// Generator](./Pulse_Generator.html) and [Pulse Latch](./Pulse_Latch.html)
// would be handy here to handle the state transitions.

`default_nettype none

module Synchronous_Muller_C_Element
#(
    parameter INPUT_COUNT   = 0,
    parameter PIPE_DEPTH    = 0     // Minimum of 1
)
(
    input   wire                        clock,
    input   wire                        clear,
    input   wire                        clock_enable,

    input   wire    [INPUT_COUNT-1:0]   lines_in,
    output  reg                         line_out
);

    localparam INPUT_ZERO   = {INPUT_COUNT{1'b0}};
    localparam INPUT_ONES   = {INPUT_COUNT{1'b1}};

    localparam PIPE_WIDTH   = INPUT_COUNT + 1;
    localparam PIPE_ZERO    = {(PIPE_WIDTH * PIPE_DEPTH){1'b0}};

    initial begin
        line_out = 1'b0;
    end

// Pipeline all the inputs and the combinational output together. This enables
// forward retiming for performance, and stores the output state (which is
// what makes this version synchronous). At a `PIPE_DEPTH` of 1, this behaves
// identically to having a single output register, except it can retime inside
// the feedback loop from the `line_out`.

    wire [INPUT_COUNT-1:0]  lines_in_pipelined;
    wire                    line_out_pipelined;

    Register_Pipeline
    #(
        .WORD_WIDTH (PIPE_WIDTH),
        .PIPE_DEPTH (PIPE_DEPTH),
        // concatenation of each stage initial/reset value
        .RESET_VALUES   (PIPE_ZERO)
    )
    input_pipeline
    (
        .clock          (clock),
        .clock_enable   (clock_enable),
        .clear          (clear),
        .parallel_load  (1'b0),
        .parallel_in    (PIPE_ZERO),
        // verilator lint_off PINCONNECTEMPTY
        .parallel_out   (),
        // verilator lint_on  PINCONNECTEMPTY
        .pipe_in        ({lines_in,             line_out}),
        .pipe_out       ({lines_in_pipelined,   line_out_pipelined})
    );

// And compute the set and hold functions based off the pipelined values.

    reg set_output  = 1'b0;
    reg hold_output = 1'b0;

    always @(*) begin
        set_output  = (lines_in_pipelined == INPUT_ONES);
        hold_output = (lines_in_pipelined != INPUT_ZERO) && (line_out_pipelined == 1'b1);
        line_out    = (set_output         == 1'b1)       || (hold_output        == 1'b1);
    end

endmodule

//# Pipeline Synchronizer (Lazy)

// Takes in two or more pipelines and synchronizes them so they can only
// complete their handshakes simultaneously, then outputs the synchronized
// handshakes. This forces data to be consumed in FIFO order and in lock-step
// for all pipelines (e.g.: addresses and data for a memory write, each from
// independent sources).

// We synchronize by first Joining the pipelines, then re-forking them and
// discarding all but one copy of the data.

// A consequence of the synchronization is that the ready signal of the input
// interfaces will only assert once *all* input valid lines are asserted. This
// is a combinational path. There is no buffering. Watch out for combinational
// loops.

//## Ports, Parameters, and Constants

`default_nettype none

module Pipeline_Synchronizer_Lazy
#(
    parameter WORD_WIDTH        = 0,
    parameter PORT_COUNT        = 0,

    // Do not set at instantiation, except in Vivado IPI
    parameter PORT_WIDTH_TOTAL  = WORD_WIDTH * PORT_COUNT
)
(
    output  wire    [PORT_COUNT-1:0]        input_data_ready,
    input   wire    [PORT_COUNT-1:0]        input_data_valid,
    input   wire    [PORT_WIDTH_TOTAL-1:0]  input_data,

    input   wire    [PORT_COUNT-1:0]        output_data_ready,
    output  wire    [PORT_COUNT-1:0]        output_data_valid,
    output  reg     [PORT_WIDTH_TOTAL-1:0]  output_data
);

    localparam PORT_WIDTH_TOTAL_ZERO = {PORT_WIDTH_TOTAL{1'b0}};

    initial begin
        output_data = PORT_WIDTH_TOTAL_ZERO;
    end

//## Input Join

    wire                        input_data_joined_valid;
    wire                        input_data_joined_ready;
    wire [PORT_WIDTH_TOTAL-1:0] input_data_joined;

    Pipeline_Join_Lazy
    #(
        .WORD_WIDTH     (WORD_WIDTH),
        .INPUT_COUNT    (PORT_COUNT)
    )
    input_join
    (
        .input_valid    (input_data_valid),
        .input_ready    (input_data_ready),
        .input_data     (input_data),

        .output_valid   (input_data_joined_valid),
        .output_ready   (input_data_joined_ready),
        .output_data    (input_data_joined)
    );

//## Output Fork

// We end up with duplicates of the input data since we are creating
// `PORT_COUNT` forked copies of all the `PORT_COUNT` input data interfaces
// joined together. So we discard all but the first copy and keep all the
// control signals.

    localparam PORT_WIDTH_TOTAL_WITH_DUPLICATES = PORT_WIDTH_TOTAL * PORT_COUNT;

    // verilator lint_off UNUSED
    wire [PORT_WIDTH_TOTAL_WITH_DUPLICATES-1:0] output_data_with_duplicates;
    // verilator lint_on  UNUSED

    Pipeline_Fork_Lazy
    #(
        .WORD_WIDTH     (PORT_WIDTH_TOTAL),
        .OUTPUT_COUNT   (PORT_COUNT)
    )
    output_fork
    (
        .input_valid    (input_data_joined_valid),
        .input_ready    (input_data_joined_ready),
        .input_data     (input_data_joined),

        .output_valid   (output_data_valid),
        .output_ready   (output_data_ready),
        .output_data    (output_data_with_duplicates)
    );

    always @(*) begin
        output_data = output_data_with_duplicates [0 +: PORT_WIDTH_TOTAL];
    end

endmodule

//# Pipeline Join (Lazy)

// Takes in multiple input ready/valid handshakes with associated data, and
// once all input handshakes can complete, joins them together into a single
// output ready/valid handshake with all data concatenated. This function
// synchronizes multiple pipelines into a single wider one.

//## Avoiding combinational loops

// As a design convention, we must avoid a combinational path between the
// valid and ready signals in a given pipeline interface, because if the other
// end of the pipeline connection also has a ready/valid combinational path,
// connecting these two interfaces will form a combinational loop, which
// cannot be analyzed for timing, or simulated reliably.

// However, there are rare cases where you do *not* want buffering, so if you
// take care about combinational delays and loops, you can use this unbuffered
// version. Otherwise, use the regular buffered [Pipeline Join]
// (./Pipeline_Join.html).

`default_nettype none

module Pipeline_Join_Lazy
#(
    parameter WORD_WIDTH     = 0,
    parameter INPUT_COUNT    = 0,

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * INPUT_COUNT
)
(
    input  wire [INPUT_COUNT-1:0]   input_valid,
    output reg  [INPUT_COUNT-1:0]   input_ready,
    input  wire [TOTAL_WIDTH-1:0]   input_data,

    output reg                      output_valid,
    input  wire                     output_ready,
    output reg  [TOTAL_WIDTH-1:0]   output_data
);

    localparam INPUT_ZERO = {INPUT_COUNT{1'b0}};
    localparam INPUT_ONES = {INPUT_COUNT{1'b1}};
    localparam TOTAL_ZERO = {TOTAL_WIDTH{1'b0}};

    initial begin
        input_ready  = INPUT_ZERO;
        output_valid = 1'b0;
        output_data  = TOTAL_ZERO;
    end

// Once all inputs are valid, declare the output valid and make all the input
// ready equal to the output ready.  Pass the input data to the output data.

    always @(*) begin
        output_valid    = (input_valid == INPUT_ONES);
        output_data     = input_data;
    end

    always @(*) begin
        input_ready     = (output_valid == 1'b1) ? {INPUT_COUNT{output_ready}} : INPUT_ZERO;
    end

endmodule

//# Pipeline Fork (Lazy)

// Takes in a ready/valid handshake along with the associated data, and
// replicates that transaction to multiple outputs. The input can proceed to
// the next transaction once **all** outputs have finished their transactions.
// *All input and output transactions complete simultaneously.*

// There is no buffering, so be careful of combinational paths. If you cannot
// avoid a long combination path (or worse, a loop), then you must use the
// [Eager Pipeline Fork](./Pipeline_Fork_Eager.html).

`default_nettype none

module Pipeline_Fork_Lazy
#(
    parameter WORD_WIDTH    = 0,
    parameter OUTPUT_COUNT  = 0,

    // Do not set at instantiation, except in IPI
    parameter TOTAL_WIDTH   = WORD_WIDTH * OUTPUT_COUNT
)
(
    input  wire                     input_valid,
    output reg                      input_ready,
    input  wire [WORD_WIDTH-1:0]    input_data,

    output reg  [OUTPUT_COUNT-1:0]  output_valid,
    input  wire [OUTPUT_COUNT-1:0]  output_ready,
    output reg  [TOTAL_WIDTH-1:0]   output_data
);

    localparam TOTAL_ZERO   = {TOTAL_WIDTH{1'b0}};
    localparam OUTPUT_ONES  = {OUTPUT_COUNT{1'b1}};
    localparam OUTPUT_ZERO  = {OUTPUT_COUNT{1'b0}};

    initial begin
        input_ready     = 1'b0;
        output_valid    = OUTPUT_ZERO;
        output_data     = TOTAL_ZERO;
    end

// If all outputs are ready, then signal ready to the input and pass the valid
// signal through to all outputs, so all transaction complete together.

    reg output_valid_gated  = 1'b0;

    always @(*) begin
        input_ready         = (output_ready == OUTPUT_ONES);
        output_valid        = {OUTPUT_COUNT{output_valid_gated}};
        output_data         = {OUTPUT_COUNT{input_data}};
    end

    always @(*) begin
        output_valid_gated  = (input_valid == 1'b1) && (input_ready == 1'b1);
    end

endmodule
